import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { Subject, lastValueFrom, takeUntil } from 'rxjs';

import { AuthService } from '../../services/timbrature-auth.adapter';
import { UsersService } from '../../services/user.service';
import { CompanyService } from '../../services/company.service';

import { User, Company } from '../../models';
import { InvitiDipendentiComponent } from '../inviti-dipendenti/inviti-dipendenti.component';
import { LUCIDE_ICONS, LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-lista-dipendenti',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule, InvitiDipendentiComponent, LucideAngularModule],
  templateUrl: './lista-dipendenti.component.html',
  styleUrls: ['./lista-dipendenti.component.css']
})
export class ListaDipendentiComponent implements OnInit, OnDestroy {
  private authService = inject(AuthService);
  private usersService = inject(UsersService);
  private companyService = inject(CompanyService);
  private router = inject(Router);

  currentUser: User | null = null;
  aziendaCorrente: Company | null = null;
  isLoading = false;
  showInvitiModal = false;

  // Liste dipendenti
  dipendentiAttivi: User[] = [];
  dipendentiCestino: User[] = [];
  dipendentiFiltratiAttivi: User[] = [];
  dipendentiFiltratiCestino: User[] = [];
  mostraDisattivati = false;
  dipendenti: User[] = [];
  dipendentiFiltrati: User[] = [];
  
  // Filtri
  filtroTesto = '';
  filtroRuolo = '';
  filtroStato = '';               // 'attivo' | 'inattivo' | ''
  filtroMansione = '';            // nome mansione o '__none__'
  jobTitles: string[] = [];        // lista mansioni uniche

  // Permessi manager
  canEditEmployees = false;

  private destroy$ = new Subject<void>();

  ngOnInit() {
    this.authService.currentUser$
      .pipe(takeUntil(this.destroy$))
      .subscribe(async (user) => {
        this.currentUser = user;
        if (!user) {
          this.resetData();
          return;
        }
        await this.loadAziendaAndData();
      });
  }

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

  private resetData() {
    this.aziendaCorrente = null;
    this.dipendentiAttivi = [];
    this.dipendentiCestino = [];
    this.dipendentiFiltratiAttivi = [];
    this.dipendentiFiltratiCestino = [];
    this.canEditEmployees = false;
  }

private async loadAziendaAndData() {
  if (!this.currentUser) return;
  this.isLoading = true;
  try {
    this.aziendaCorrente = await lastValueFrom(
      this.companyService.getForUser(this.currentUser.id, this.authService.companyId)
    );
    if (this.authService.hasRole('manager')) {
      this.computeManagerPermissions();
    } else {
      this.canEditEmployees = this.authService.hasRole('admin');
    }
    await this.loadDipendenti();
  } catch (error) {
    console.error('Errore caricamento azienda/dipendenti', error);
  } finally {
    this.isLoading = false;
  }
}

  private computeManagerPermissions() {
    if (!this.currentUser || !this.aziendaCorrente) return;
    const config = this.companyService.resolveManagerConfig(
      this.aziendaCorrente,
      this.currentUser.id
    );
    this.canEditEmployees = config.can_edit_employees ?? false;
  }

private async loadDipendenti() {
  const companyId = this.authService.companyId;
  console.log('🔍 loadDipendenti - companyId:', companyId);
  if (!companyId) {
    this.dipendentiAttivi = [];
    this.dipendentiCestino = [];
    this.applicaFiltri();
    return;
  }
  try {
    const all = await lastValueFrom(
      this.usersService.getByCompany(companyId)
    );
    let filtered = all;
    if (this.authService.hasRole('manager') && this.aziendaCorrente) {
      filtered = this.companyService.filterEmployeesByVisibility(
        all,
        this.aziendaCorrente,
        this.currentUser!.id
      );
    }
    this.dipendentiAttivi = filtered.filter(u => u.is_active && !(u as any).deleted_at);
    this.dipendentiCestino = filtered.filter(u => (u as any).deleted_at);
    this.dipendenti = [...this.dipendentiAttivi, ...this.dipendentiCestino];
    this.jobTitles = [...new Set(filtered.map(u => u.job_title).filter(Boolean))] as string[];
    this.applicaFiltri();
  } catch (error) {
    console.error('Errore caricamento dipendenti', error);
  }
}

  applicaFiltri() {
    const testo = this.filtroTesto.toLowerCase();
    const ruolo = this.filtroRuolo;
    const mansione = this.filtroMansione;
    const stato = this.filtroStato;

    const filterFn = (u: User) => {
      // Filtro mansione
      if (mansione) {
        if (mansione === '__none__') {
          if (u.job_title) return false;
        } else {
          if ((u.job_title || '').toLowerCase() !== mansione.toLowerCase()) return false;
        }
      }
      // Filtro ruolo
      if (ruolo && u.role !== ruolo) return false;
      // Filtro stato (attivo/inattivo) – per la lista attivi, per il cestino questo filtro potrebbe essere ignorato
      if (stato === 'attivo' && !u.is_active) return false;
      if (stato === 'inattivo' && u.is_active) return false;
      // Filtro testo libero
      if (testo) {
        const fullText = `${u.first_name} ${u.last_name} ${u.email}`.toLowerCase();
        if (!fullText.includes(testo)) return false;
      }
      return true;
    };

    this.dipendentiFiltratiAttivi = this.dipendentiAttivi.filter(filterFn);
    this.dipendentiFiltratiCestino = this.dipendentiCestino.filter(filterFn);

    // Aggiorna l'array da visualizzare in base allo stato del toggle
    this.dipendentiFiltrati = this.mostraDisattivati ? this.dipendentiFiltratiCestino : this.dipendentiFiltratiAttivi;
  }

  toggleMostraDisattivati() {
    this.mostraDisattivati = !this.mostraDisattivati;
    this.applicaFiltri();
  }

  onFiltroChange() {
    this.applicaFiltri();
  }

  // Gestione modale inviti
  openInvitiModal() {
    if (!this.aziendaCorrente?.id) {
      alert('Azienda non disponibile. Impossibile invitare dipendenti.');
      return;
    }
    this.showInvitiModal = true;
  }

  closeInvitiModal() {
    this.showInvitiModal = false;
    // Ricarica i dipendenti dopo l'invito
    this.loadDipendenti();
  }

  // Azioni sui dipendenti

  // Attiva/disattiva (cambia is_active)
  async cambiaStatoDipendente(d: User) {
    if (!d.id) return;
    const targetState = !d.is_active;
    const action = targetState ? 'attivare' : 'disattivare';
    if (!confirm(`Vuoi ${action} il dipendente ${d.first_name} ${d.last_name}?`)) return;
    this.isLoading = true;
    try {
      await lastValueFrom(
        this.usersService.setActiveStatus(d.id, targetState, d.company_id ?? undefined)
      );
      await this.loadDipendenti();
    } catch (error) {
      console.error('Errore cambio stato', error);
      alert('Errore durante l\'operazione');
    } finally {
      this.isLoading = false;
    }
  }

  // Sposta nel cestino (soft delete)
  async eliminaDipendente(d: User) {
    if (!d.id) return;
    if (!confirm(`Sei sicuro di voler spostare nel cestino ${d.first_name} ${d.last_name}?`)) return;
    this.isLoading = true;
    try {
      await lastValueFrom(
        this.usersService.softDelete(d.id, this.currentUser!.id, d.company_id ?? undefined)
      );
      await this.loadDipendenti();
    } catch (error) {
      console.error('Errore eliminazione', error);
      alert('Errore durante l\'eliminazione');
    } finally {
      this.isLoading = false;
    }
  }

  // Ripristina dal cestino (restore)
  async riattivaDipendente(d: User) {
    if (!d.id) return;
    if (!confirm(`Vuoi riattivare ${d.first_name} ${d.last_name}?`)) return;
    this.isLoading = true;
    try {
      await lastValueFrom(this.usersService.restore(d.id, d.company_id ?? undefined));
      await this.loadDipendenti();
    } catch (error) {
      console.error('Errore ripristino', error);
      alert('Errore durante il ripristino');
    } finally {
      this.isLoading = false;
    }
  }

  // Navigazione al dettaglio
apriDettaglio(id: string, event?: MouseEvent) {
  event?.preventDefault();
  if (this.authService.hasRole('manager') && !this.canEditEmployees) {
    alert('Non hai i permessi per vedere i dettagli dei dipendenti.');
    return;
  }
  this.router.navigate(['/restaurant/timbrature/dipendenti', id]);
}

  // Utility
  hasRole(role: string): boolean {
    return this.authService.hasRole(role);
  }

  trackById(index: number, item: User) {
    return item.id;
  }
}
